import{_ as t,c as a,o as e,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"使用指南: 斜杠命令和自然语言 | opencode-mystatus","description":"学习 opencode-mystatus 的两种使用方式。通过斜杠命令和自然语言提问，快速查询多个 AI 平台的额度使用情况。","frontmatter":{"title":"使用指南: 斜杠命令和自然语言 | opencode-mystatus","sidebarTitle":"使用方式","subtitle":"使用指南: 斜杠命令和自然语言","description":"学习 opencode-mystatus 的两种使用方式。通过斜杠命令和自然语言提问，快速查询多个 AI 平台的额度使用情况。","tags":["快速开始","斜杠命令","自然语言"],"prerequisite":["start-quick-start"],"order":2},"headers":[],"relativePath":"zh/vbgate/opencode-mystatus/start/using-mystatus/index.md","filePath":"zh/vbgate/opencode-mystatus/start/using-mystatus/index.md"}'),i={name:"zh/vbgate/opencode-mystatus/start/using-mystatus/index.md"};function o(l,s,p,d,h,r){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="使用-mystatus-斜杠命令和自然语言" tabindex="-1">使用 mystatus：斜杠命令和自然语言 <a class="header-anchor" href="#使用-mystatus-斜杠命令和自然语言" aria-label="Permalink to &quot;使用 mystatus：斜杠命令和自然语言&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>使用 <code>/mystatus</code> 斜杠命令一键查询所有 AI 平台额度</li><li>用自然语言提问让 OpenCode 自动调用 mystatus 工具</li><li>理解斜杠命令和自然语言两种触发方式的区别和适用场景</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你在使用多个 AI 平台开发（OpenAI、智谱 AI、GitHub Copilot 等），想知道每个平台还剩多少额度，但不想逐个登录各平台查看——太麻烦了。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li><strong>需要快速查看所有平台额度时</strong>：每天开发前检查一下，合理安排使用</li><li><strong>想知道某个平台具体额度时</strong>：比如想确认 OpenAI 是否快用完了</li><li><strong>想检查配置是否生效时</strong>：刚配置好新账号，验证一下能否正常查询</li></ul><div class="info custom-block"><p class="custom-block-title">前置检查</p><p>本教程假设你已完成<a href="/docs/opencodedocs/zh/vbgate/opencode-mystatus/start/quick-start/">opencode-mystatus 插件安装</a>。如果还没有安装，请先完成安装步骤。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>opencode-mystatus 提供了两种触发 mystatus 工具的方式：</p><ol><li><strong>斜杠命令 <code>/mystatus</code></strong>：快速、直接、无歧义，适合频繁查询</li><li><strong>自然语言提问</strong>：更灵活，适合结合具体场景的查询</li></ol><p>两种方式都会调用同一个 <code>mystatus</code> 工具，工具会并行查询所有已配置的 AI 平台额度，返回带进度条、使用统计和重置倒计时的结果。</p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-使用斜杠命令查询额度" tabindex="-1">第 1 步：使用斜杠命令查询额度 <a class="header-anchor" href="#第-1-步-使用斜杠命令查询额度" aria-label="Permalink to &quot;第 1 步：使用斜杠命令查询额度&quot;">​</a></h3><p>在 OpenCode 中输入以下命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>为什么</strong> 斜杠命令是 OpenCode 的快捷命令机制，可以快速调用预定义的工具。<code>/mystatus</code> 命令会直接调用 mystatus 工具，无需额外参数。</p><p><strong>你应该看到</strong>： OpenCode 会返回所有已配置平台的额度信息，格式如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI 账号额度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (team)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3小时限额</span></span>
<span class="line"><span>████████████████████████████ 剩余 85%</span></span>
<span class="line"><span>重置: 2h 30m后</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 智谱 AI 账号额度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        9c89****AQVM (Coding Plan)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5小时 token 限额</span></span>
<span class="line"><span>████████████████████████████ 剩余 95%</span></span>
<span class="line"><span>已用: 0.5M / 10.0M</span></span>
<span class="line"><span>重置: 4h后</span></span></code></pre></div><p>每个平台会显示：</p><ul><li>账号信息（邮箱或脱敏后的 API Key）</li><li>进度条（可视化显示剩余额度）</li><li>重置时间倒计时</li><li>已用量和总用量（部分平台）</li></ul><h3 id="第-2-步-用自然语言提问" tabindex="-1">第 2 步：用自然语言提问 <a class="header-anchor" href="#第-2-步-用自然语言提问" aria-label="Permalink to &quot;第 2 步：用自然语言提问&quot;">​</a></h3><p>除了斜杠命令，你也可以用自然语言提问，OpenCode 会自动识别意图并调用 mystatus 工具。</p><p>试试这些提问方式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenAI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span></span></code></pre></div><p>或</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">How</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> much</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> have</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> left?</span></span></code></pre></div><p>或</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p><strong>为什么</strong> 自然语言查询更符合日常对话习惯，适合在具体开发场景中提出问题。OpenCode 会通过语义匹配识别出你想查询额度，并自动调用 mystatus 工具。</p><p><strong>你应该看到</strong>： 与斜杠命令相同的输出结果，只是触发方式不同。</p><h3 id="第-3-步-理解斜杠命令的配置" tabindex="-1">第 3 步：理解斜杠命令的配置 <a class="header-anchor" href="#第-3-步-理解斜杠命令的配置" aria-label="Permalink to &quot;第 3 步：理解斜杠命令的配置&quot;">​</a></h3><p>斜杠命令 <code>/mystatus</code> 是如何工作的？它是在 OpenCode 配置文件中定义的。</p><p>打开 <code>~/.config/opencode/opencode.json</code>，找到 <code>command</code> 部分：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opencode-mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Query quota usage for all AI accounts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;template&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Use the mystatus tool to query quota usage. Return the result as-is without modification.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>关键配置项说明</strong>：</p><table tabindex="0"><thead><tr><th>配置项</th><th>值</th><th>作用</th></tr></thead><tbody><tr><td><code>description</code></td><td>&quot;Query quota usage for all AI accounts&quot;</td><td>在命令列表中显示的说明</td></tr><tr><td><code>template</code></td><td>&quot;Use to mystatus tool...&quot;</td><td>提示 OpenCode 如何处理这个命令</td></tr></tbody></table><p><strong>为什么需要 template</strong> template 是给 OpenCode 的&quot;指令&quot;，告诉它：当用户输入 <code>/mystatus</code> 时，调用 mystatus 工具，并将结果原样返回给用户（不做任何修改）。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>确认你已经掌握了两种使用方式：</p><table tabindex="0"><thead><tr><th>技能</th><th>检查方法</th><th>预期结果</th></tr></thead><tbody><tr><td>斜杠命令查询</td><td>输入 <code>/mystatus</code></td><td>显示所有平台的额度信息</td></tr><tr><td>自然语言查询</td><td>输入 &quot;Check my OpenAI quota&quot;</td><td>显示额度信息</td></tr><tr><td>理解配置</td><td>查看 opencode.json</td><td>找到 mystatus 命令配置</td></tr></tbody></table><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="常见错误-1-斜杠命令无响应" tabindex="-1">常见错误 1：斜杠命令无响应 <a class="header-anchor" href="#常见错误-1-斜杠命令无响应" aria-label="Permalink to &quot;常见错误 1：斜杠命令无响应&quot;">​</a></h3><p><strong>现象</strong>：输入 <code>/mystatus</code> 后没有任何反应</p><p><strong>原因</strong>：OpenCode 配置文件没有正确配置斜杠命令</p><p><strong>解决方法</strong>：</p><ol><li>打开 <code>~/.config/opencode/opencode.json</code></li><li>确认 <code>command</code> 部分包含 <code>mystatus</code> 配置（见第 3 步）</li><li>重启 OpenCode</li></ol><h3 id="常见错误-2-自然语言提问没有调用-mystatus-工具" tabindex="-1">常见错误 2：自然语言提问没有调用 mystatus 工具 <a class="header-anchor" href="#常见错误-2-自然语言提问没有调用-mystatus-工具" aria-label="Permalink to &quot;常见错误 2：自然语言提问没有调用 mystatus 工具&quot;">​</a></h3><p><strong>现象</strong>：输入 &quot;Check my OpenAI quota&quot; 后，OpenCode 没有调用 mystatus 工具，而是尝试自己回答</p><p><strong>原因</strong>：OpenCode 没有正确识别你的意图</p><p><strong>解决方法</strong>：</p><ol><li>尝试更明确的表达：&quot;Use mystatus tool to check my OpenAI quota&quot;</li><li>或直接使用斜杠命令 <code>/mystatus</code>，更可靠</li></ol><h3 id="常见错误-3-显示-未找到任何已配置的账号" tabindex="-1">常见错误 3：显示&quot;未找到任何已配置的账号&quot; <a class="header-anchor" href="#常见错误-3-显示-未找到任何已配置的账号" aria-label="Permalink to &quot;常见错误 3：显示&quot;未找到任何已配置的账号&quot;&quot;">​</a></h3><p><strong>现象</strong>：执行 <code>/mystatus</code> 后显示&quot;未找到任何已配置的账号&quot;</p><p><strong>原因</strong>：还没有配置任何平台的认证信息</p><p><strong>解决方法</strong>：</p><ul><li>至少配置一个平台的认证信息（OpenAI、智谱 AI、Z.ai、GitHub Copilot 或 Google Cloud）</li><li>详见 <a href="/docs/opencodedocs/zh/vbgate/opencode-mystatus/start/quick-start/">快速开始教程</a> 中的配置说明</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>mystatus 工具提供了两种使用方式：</p><ol><li><strong>斜杠命令 <code>/mystatus</code></strong>：快速直接，适合频繁查询</li><li><strong>自然语言提问</strong>：更灵活，适合结合具体场景</li></ol><p>两种方式都会并行查询所有已配置的 AI 平台额度，返回带进度条和重置倒计时的结果。斜杠命令的配置在 <code>~/.config/opencode/opencode.json</code> 中定义，通过 template 指示 OpenCode 如何调用 mystatus 工具。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="/docs/opencodedocs/zh/vbgate/opencode-mystatus/start/understanding-output/">解读输出：进度条、重置时间和多账号</a></strong>。</p><p>你会学到：</p><ul><li>如何解读进度条的含义</li><li>重置时间倒计时如何计算</li><li>多账号场景下的输出格式</li><li>进度条生成原理</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>mystatus 工具定义</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>29-33</td></tr><tr><td>工具描述</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>30-31</td></tr><tr><td>斜杠命令配置</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/command/mystatus.md" target="_blank" rel="noreferrer"><code>command/mystatus.md</code></a></td><td>1-6</td></tr><tr><td>并行查询所有平台</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>49-56</td></tr><tr><td>结果收集和汇总</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>58-89</td></tr></tbody></table><p><strong>关键常量</strong>： 无（本节主要介绍调用方式，不涉及具体常量）</p><p><strong>关键函数</strong>：</p><ul><li><code>mystatus()</code>：mystatus 工具的主函数，读取认证文件并并行查询所有平台（<code>plugin/mystatus.ts:29-33</code>）</li><li><code>collectResult()</code>：收集查询结果到 results 和 errors 数组（<code>plugin/mystatus.ts:100-116</code>）</li></ul></details>`,66)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
